import sys

def read_file(filename):
    contents = open(filename, 'r').read()
    return contents

def find_most_common_letter(contents):
    character_count = {}
    for letter in contents:
        if letter.isalpha() and letter.strip():
            if letter.upper() in character_count:
                character_count[letter.upper()] += 1
            else:
                character_count[letter.upper()] = 1
    most_common_letter = max(character_count, key=character_count.get)
    return most_common_letter, character_count[most_common_letter]

def find_percentage_of_word(contents, word):
    word_count = 0
    total_words = len(contents.split())
    for w in contents.split():
        if w.lower() == word:
            word_count += 1
    percent = (word_count / total_words) * 100
    return int(percent)

def write_first_10_words_to_file(contents):
    words = contents.split()[:10]
    with open('Exercise_8_output.txt', 'w') as f:
        f.write(' '.join(words))

if __name__ == "__main__":
    filename = sys.argv[1]
    contents = read_file(filename)
    most_common_letter, count = find_most_common_letter(contents)
    print(f"{most_common_letter} is the most common letter. It occurs {count} times.")
    percent = find_percentage_of_word(contents, 'the')
    print(f"The percentage of the number of words that is 'the' is {percent}%")
    write_first_10_words_to_file(contents)
```

You can save this code as "exercise8.py" and run it with the filename as an argument in the command line. For example:

```
python exercise8.py my_file.txt
```

Note that the code assumes that the file is in the same directory as the Python script.
